// Skriv din algoritm här. Du MÅSTE returnera ett objekt med:
// { question: string, answer: string, clues: array }

const namesList = ["Albin", "Stina", "Rickard", "Elin", "Oskar", "Maja", "Leo", "Klara", "Ali", "Sara"];

const scenarios = [
  {
    type: "money",
    verb: "fick",
    intro: "delade på vinsten från ett lotteri",
    questionTmpl: "Hur mycket fick {target}?",
    totalTmpl: "Tillsammans vann de {total} kr."
  },
  {
    type: "countable",
    verb: "plockade",
    intro: "plockade äpplen i farfars trädgård",
    questionTmpl: "Hur många äpplen plockade {target}?",
    totalTmpl: "Tillsammans plockade de {total} äpplen."
  },
  {
    type: "countable",
    verb: "fick",
    intro: "delade på en stor påse lördagsgodis",
    questionTmpl: "Hur många godisbitar fick {target}?",
    totalTmpl: "Totalt fanns det {total} godisbitar i påsen."
  },
  {
    type: "countable",
    verb: "fick",
    intro: "fick poäng i en lokal tv-spelsturnering",
    questionTmpl: "Hur många poäng slutade {target} med?",
    totalTmpl: "Tillsammans skrapade de ihop {total} poäng."
  }
];

// Hjälpfunktion för att plocka unika namn
function getRandomNames(arr, count) {
  const shuffled = [...arr].sort(() => 0.5 - Math.random());
  return shuffled.slice(0, count);
}

// Hjälpfunktion för att generera en naturlig text för relationen
function generateRelationText(name1, name2, scenario, relType, val) {
  const isMoney = scenario.type === "money";
  const muchMany = isMoney ? "mycket" : "många";
  const more = isMoney ? "mer" : "fler";
  const less = isMoney ? "mindre" : "färre";

  if (relType === "mult") {
    if (val === 2) return `${name1} ${scenario.verb} dubbelt så ${muchMany} som ${name2}.`;
    if (val === 3) return `${name1} ${scenario.verb} tre gånger så ${muchMany} som ${name2}.`;
    return `${name1} ${scenario.verb} ${val} gånger så ${muchMany} som ${name2}.`; 
  } else {
    if (val > 0) return `${name1} ${scenario.verb} ${isMoney ? val + " kr" : val} ${more} än ${name2}.`;
    return `${name1} ${scenario.verb} ${isMoney ? Math.abs(val) + " kr" : Math.abs(val)} ${less} än ${name2}.`;
  }
}

let attempts = 0;
let validPuzzleFound = false;
let finalQuestion, finalAnswer, finalClues;

while (attempts < 100 && !validPuzzleFound) {
  attempts++;

  // 1. Plocka 3 slumpmässiga namn (A, B, C) och ett scenario
  const selectedNames = getRandomNames(namesList, 3);
  const [A, B, C] = selectedNames;
  const scenario = scenarios[Math.floor(Math.random() * scenarios.length)];
  const isMoney = scenario.type === "money";

  // 2. Skapa basvärdet för C (Se till att det blir jämna tior om det är pengar)
  let valC = isMoney ? (Math.floor(Math.random() * 8) + 2) * 20 : Math.floor(Math.random() * 10) + 5;

  // 3. Skapa relation B till C (kan vara multiplikation eller addition)
  let relType1 = Math.random() > 0.5 ? "mult" : "add";
  let relVal1, valB;
  if (relType1 === "mult") {
    relVal1 = Math.floor(Math.random() * 2) + 2; // Gånger 2 eller 3
    valB = valC * relVal1;
  } else {
    let maxOffset = isMoney ? 100 : 8;
    let step = isMoney ? 10 : 1;
    do {
      relVal1 = (Math.floor(Math.random() * (maxOffset/step * 2)) - maxOffset/step) * step;
    } while (relVal1 === 0); // Undvik "fick 0 mer än"
    valB = valC + relVal1;
  }

  // 4. Skapa relation A till B
  let relType2 = Math.random() > 0.5 ? "mult" : "add";
  let relVal2, valA;
  if (relType2 === "mult") {
    relVal2 = Math.floor(Math.random() * 2) + 2;
    valA = valB * relVal2;
  } else {
    let maxOffset = isMoney ? 100 : 8;
    let step = isMoney ? 10 : 1;
    do {
      relVal2 = (Math.floor(Math.random() * (maxOffset/step * 2)) - maxOffset/step) * step;
    } while (relVal2 === 0);
    valA = valB + relVal2;
  }

  const total = valA + valB + valC;

  // 5. Strikt validering: Alla måste ha fått något (>0), svaret ska vara jämnt
  if (valA > 0 && valB > 0 && valC > 0 && total > 0 && Number.isInteger(total)) {

    // Bygg ihop strängarna
    const clueTotal = `${A}, ${B} och ${C} ${scenario.intro}. ${scenario.totalTmpl.replace("{total}", total)}`;
    const clueRel1 = generateRelationText(B, C, scenario, relType1, relVal1);
    const clueRel2 = generateRelationText(A, B, scenario, relType2, relVal2);

    const clues = [clueTotal, clueRel1, clueRel2];
    clues.sort(() => 0.5 - Math.random()); // Blanda ledtrådarna så strukturen inte är uppenbar

    // Välj slumpmässigt vem frågan ska handla om
    const targetIdx = Math.floor(Math.random() * 3);
    const targetName = selectedNames[targetIdx];
    const targetVal = targetIdx === 0 ? valA : targetIdx === 1 ? valB : valC;

    finalQuestion = scenario.questionTmpl.replace("{target}", targetName);
    finalAnswer = targetVal.toString();
    finalClues = clues;
    validPuzzleFound = true;
  }
}

// Failsafe om loopen på något magiskt sätt skulle misslyckas
if (!validPuzzleFound) {
  finalQuestion = "Hur många godisbitar fick Albin?";
  finalAnswer = "16";
  finalClues = [
    "Albin, Stina och Rickard delade på en stor påse lördagsgodis. Totalt fanns det 29 godisbitar i påsen.",
    "Albin fick dubbelt så många som Stina.",
    "Stina fick 3 fler än Rickard."
  ];
  finalClues.sort(() => 0.5 - Math.random());
}

return {
  question: finalQuestion,
  answer: finalAnswer,
  clues: finalClues
};
